#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    // For each string, compute net balance and min prefix balance.
    // We classify strings into:
    //   balanced (net = 0, min >= 0) -> these are "perfect"
    //   net > 0 (more '(' than ')') -> we need to pair with net < 0
    //   net < 0 (more ')' than '(')
    // For net > 0 strings, we need to ensure min prefix >= 0 when concatenating
    //   after some stuff. Actually we need to consider "left" (net > 0) and "right" (net < 0).
    // For a left string, its contribution to prefix is +net. But we need that
    //   when concatenating left + right, the combined never negative.
    // More carefully: when we concatenate two strings A then B, the result is
    //   valid iff both A is a valid prefix (min prefix of A >= 0) and
    //   (total balance of A + min prefix of B) >= 0.
    // Since we pair them, we can reorder. The optimal strategy:
    //   - Pair a "left" (net > 0) with a "right" (net < 0).
    //   - For left strings, we sort by "need" = -min_prefix (how many '(' we need before it? Actually min_prefix is negative if it dips).
    //     Wait, for a left string (net > 0), the min prefix could be negative (e.g. ")(" ).
    //     Let's think: For a string to serve as left side of a pair, we need its min_prefix >= 0 OR if it's negative,
    //     we need some prefix buffer. However, when concatenating sequences arbitrarily, we can reorder them.
    // 
    // Actually, a classic approach for "maximum pairs that concatenate to correct bracket sequence":
    // We process each string and compute:
    //   balance = total '(' - ')'
    //   min_prefix = minimum prefix balance while scanning
    // 
    // A correct bracket sequence overall has balance 0 and never negative.
    // 
    // We can think of each string as a "piece" with:
    //   - need: how many '(' it requires to not go negative = -min_prefix (if min_prefix < 0, else 0)
    //   - give: total balance (net)
    // 
    // For a piece to be concatenatable with others on the left, the net balance before it must be >= need.
    // 
    // To maximize pairs, we can pair "left" pieces (net > 0) with "right" pieces (net < 0) such that
    //   left.give >= right.need and left.need == 0? Actually left side piece must have min_prefix >= 0
    //   to be placed first? Not exactly — we can arrange multiple pieces.
    //
    // Simpler known solution to this SPOJ problem (RGB7577):
    // - Count how many strings are already perfectly balanced (net=0, min>=0). These can pair with each other.
    // - For strings with net > 0, store pair (need, give) where need = -min_prefix, give = net.
    //   Only consider those where min_prefix >= 0? Actually a net > 0 string with negative min_prefix
    //   cannot be placed at the very start, but could be placed after some other string that provides enough '('.
    //   For pairing (matching two strings), we will pair one net>0 with one net<0.
    //   For net>0 to be the left string, it must have min_prefix >= 0 (so it doesn't go negative on its own).
    //   For net<0 to be the right string, its min_prefix (when scanning from left) must be >= 0? No, 
    //   it's the right string, its internal min prefix just needs to not go negative given the prefix from left.
    //   Actually for concatenation A+B to be correct: A must be correct (min_prefix_A >= 0, net_A >= 0)
    //   and B's min_prefix when scanned from net_A must be >= 0.
    //   So A must have min_prefix >= 0. B can have negative min_prefix as long as net_A >= -min_prefix_B.
    //
    //   So left strings must have min_prefix >= 0. Right strings can have any min_prefix.
    // 
    //   Hmm let's re-read the problem: "хамгийн олон хосын тоог ол" — maximum number of pairs.
    //   I think we are pairing up two sequences, concatenating them (in some order), to get a correct sequence.
    //   Each sequence used at most once. Count max pairs.
    // 
    // Yes: given n sequences, we can pair them up (each used at most once), concatenate each pair (in either order),
    // and we want the maximum number of pairs that form a correct bracket sequence.
    //
    // So we need to match left and right sequences.
    //
    // For a pair (a, b), we can try a+b or b+a (order matters).
    //
    // Let for each string compute:
    //   bal = total balance
    //   minpref = minimum prefix balance
    //
    // For a+b to be correct:
    //   minpref_a >= 0  (a never goes negative)
    //   bal_a + minpref_b >= 0
    //   bal_a + bal_b == 0
    //
    // Similarly b+a:
    //   minpref_b >= 0
    //   bal_b + minpref_a >= 0
    //   bal_a + bal_b == 0
    //
    // So to pair two strings, at least one of them must have minpref >= 0 (to go first).
    // Actually both conditions require the first string to have minpref >= 0.
    //
    // For strings with bal > 0, they can only be first in a pair (since they have excess '(').
    // For strings with bal < 0, they can only be second.
    // Strings with bal == 0 can be first if minpref >= 0 (perfect), or second if minpref < 0
    //   (actually if bal=0 and minpref<0, it can't be first; can it be second? 
    //    For a+b: bal_a + minpref_b >= 0 => minpref_b >= -bal_a. If bal_a >= 0, that's fine.
    //    So bal=0, minpref<0 strings can be second if bal_a >= -minpref_b.)
    //
    // But the simplest known solution for "pairs of bracket sequences" problem:
    // we categorize each string by (open_needed, open_given) where
    // open_given = total '(' - ')'  (net balance)
    // open_needed = -min(0, min_pref)  (how many '(' needed before it to keep non-negative)
    //
    // Then:
    // - If bal == 0 and minpref >= 0: it's a perfect string, count them separately. Pair them among themselves.
    // - For bal > 0: it has give = bal, need = -minpref (if minpref < 0, else 0). Only useful as left string if need == 0? 
    //   Actually if minpref < 0, it needs some '(' prefix, but as a left string in a pair, there's nothing before it.
    //   So it cannot be the first in a pair. But could it be second? bal > 0, so as second, the total balance would be > 0. No.
    //   So bal > 0 strings with minpref < 0 are useless for pairing (can't be first or second).
    //   Similarly bal < 0 strings with... hmm.
    //
    // Let's think more carefully with standard known problem "Bracket Sequencing" or "RGB7577".
    // I recall a problem: given n bracket sequences, find max pairs that concatenate to correct sequence.
    // Solution: 
    // 1. Count perfect strings (bal=0, minpref>=0). Pair them: cnt/2.
    // 2. For strings with bal > 0 and minpref >= 0: these are "left" strings. Store need=0, give=bal.
    //    Actually if minpref >= 0, need=0.
    // 3. For strings with bal < 0: compute "need" = -minpref (if minpref < 0, else 0)?? No, we need to know
    //    how many '(' it needs at start. Actually for a string with bal < 0, we can compute:
    //    need = -minpref (the minimum prefix negativity). If minpref >= 0, then need=0.
    //    give = bal (negative).
    //    When it's placed second, we need left_give >= need (where need is how many '(' it needs to not go negative).
    //    
    //    For a string with bal < 0 to be useful as the second in a pair, its need must be satisfiable.
    //    We can store them as (need, -bal) perhaps? Actually we want to match left (give = surplus '(')
    //    with right (need '(', give negative).
    //
    // Let left strings = those with bal > 0 and minpref >= 0. These have need=0, give=bal.
    // Let right strings = those with bal < 0. For each, compute the minimum prefix balance.
    //    If minpref >= 0, then need=0 internally? But bal is negative, so eventually it goes negative.
    //    Actually if bal < 0 but minpref >= 0, e.g. "())": prefixes: ( = 1, (( = 2... no that doesn't work.
    //    Let's try "())(()" - bal = 0? Not. Actually a string with bal < 0 must have some negative minpref.
    //    Let's compute minpref = minimum prefix balance. For "())": prefixes: 1, 0, -1 -> minpref=-1.
    //    For any string with bal < 0, minpref must be < 0 (since final bal is negative, it must dip below 0 somewhere).
    //    So need = -minpref > 0 for all bal < 0 strings.
    //
    // For right strings, we want to match them with left strings where left.give >= right.need.
    // Also the combined balance must be 0, so left.give + right.give = 0 => left.give = -right.give.
    // So a left string with give=X can only pair with a right string with give=-X AND need <= X.
    //
    // So we can count left strings by give value, and right strings by (need, give) pairs.
    // For each left give=X, we look for right strings with give=-X and need <= X.
    //
    // This can be done by sorting right strings by need and processing.
    //
    // Also what about bal=0 strings with minpref<0? e.g. ")(": bal=0, minpref=-1.
    // Can this pair with anything? If it's second, we need left give >= 1. If it's first, minpref<0 so cannot.
    // If paired with another such string? )(()( -> )(()( is not correct.
    // Actually ")(" + ")(" = ")()(" -> prefixes: -1 (invalid). 
    // So these are useless unless paired with a left string that gives enough '('.
    // Give=0, so they need X=0 from left... but need=1. Not possible.
    // So bal=0, minpref<0 strings are useless? Let's check: could they pair with a left string bal>0?
    // For a+b: bal_a > 0, bal_b = 0 => combined bal > 0, not correct.
    // For b+a: bal_b = 0, minpref_b < 0 => b can't be first.
    // So yes, useless.
    //
    // OK. Let's implement the known solution.

    // Count of perfect strings (bal=0, minpref>=0)
    // For others:
    //   left[bal] = count of strings with bal>0, minpref>=0
    //   right: vector of (need, give) for bal<0 strings
    //   But we need to pair exactly give_left = -give_right.
    // 
    // For each bal value b from 1 to max_bal (<= total_len), let cnt_left = left[b].
    // We need to match with right strings where give = -b and need <= b.
    // Among right strings with give=-b, we can match up to cnt_left of them, but only those with need <= b.
    //
    // So for each give value (negative), we collect the needs.
    // Then for each b, we sort the needs for -b, and greedily match up to cnt_left of them.

    // Total length constraint ensures O(total_len log total_len) is fine.

    const int MAXL = 500000;
    vector<int> left(MAXL + 1, 0); // left[bal] for bal>0
    // For right strings, group by give (which is negative, so we use give = -bal > 0)
    // right[give] = vector of needs
    vector<vector<int>> right(MAXL + 1);

    int perfect = 0;

    for (int i = 0; i < n; i++) {
        string s;
        cin >> s;
        int bal = 0;
        int minpref = 0;
        for (char c : s) {
            if (c == '(') bal++;
            else bal--;
            minpref = min(minpref, bal);
        }
        if (bal == 0 && minpref >= 0) {
            perfect++;
        } else if (bal > 0 && minpref >= 0) {
            if (bal <= MAXL) left[bal]++;
        } else if (bal < 0) {
            // need = -minpref (minimum prefix, which is negative, so need > 0)
            int need = -minpref; 
            int give = -bal; // positive, the surplus of ')' that needs to be matched
            if (give <= MAXL) {
                right[give].push_back(need);
            }
        }
        // other cases (bal>0 with minpref<0, bal<0 with minpref>=0 impossible) are ignored
    }

    long long ans = perfect / 2; // pair perfect strings among themselves

    // For each possible give value for left strings
    for (int g = 1; g <= MAXL; g++) {
        if (left[g] == 0) continue;
        auto& vec = right[g]; // right strings with give = g (i.e. bal = -g)
        sort(vec.begin(), vec.end());
        int matched = 0;
        for (int need : vec) {
            if (need <= g && matched < left[g]) {
                matched++;
            } else if (need > g) {
                break;
            }
        }
        ans += matched;
    }

    cout << ans << "\n";

    return 0;
}
